parameters.jsCode:
// Build SMS message for Twilio delivery
const callerName = items[0].json.caller_name || 'there';
const callerPhone = (items[0].json.caller_phone || '').replace(/[\s\-()\+]/g, '');
const callId = items[0].json.call_id || '';
const insuranceType = (items[0].json.insurance_type || 'auto').toLowerCase().trim();
const toolCallId = items[0].json.toolCallId || '';

// Strip leading '1' if 11 digits (US country code)
let phone10 = callerPhone;
if (phone10.length === 11 && phone10.startsWith('1')) {
  phone10 = phone10.substring(1);
}

if (phone10.length !== 10) {
  return [{
    json: {
      error: true,
      message: 'Invalid phone number: ' + callerPhone + ' (need 10 digits)',
      toolCallId
    }
  }];
}

// Format as E.164 for Twilio
const e164Phone = '+1' + phone10;

// Google Form URLs by insurance type
const FORM_URLS = {
  auto:             'https://docs.google.com/forms/d/1nXAAS4HKmuoofX9dqK5vF_llri1zEEThAyOJBI-midk/viewform',
  vehicle:          'https://docs.google.com/forms/d/1nXAAS4HKmuoofX9dqK5vF_llri1zEEThAyOJBI-midk/viewform',
  commercial_auto:  'https://docs.google.com/forms/d/1ye5IHu-M60EVFPcmfYjQ53zoHLFVSuOp9yoVJ-dYmFY/viewform',
  business:         'https://docs.google.com/forms/d/1ye5IHu-M60EVFPcmfYjQ53zoHLFVSuOp9yoVJ-dYmFY/viewform',
  homeowners:       'https://docs.google.com/forms/d/1ZkpKXF_ikkMHCrbYMa7Nw5M8x7STbU6nOXe18kSa0RI/viewform',
  home:             'https://docs.google.com/forms/d/1ZkpKXF_ikkMHCrbYMa7Nw5M8x7STbU6nOXe18kSa0RI/viewform',
  property:         'https://docs.google.com/forms/d/1ZkpKXF_ikkMHCrbYMa7Nw5M8x7STbU6nOXe18kSa0RI/viewform',
  condo:            'https://docs.google.com/forms/d/1a4SelYXb12Ihofm2G4Z8Kmj1vilLvhcFI5QvzufBg_4/viewform',
  renters:          'https://docs.google.com/forms/d/1UJZb20UgfubgeLkqe3BhmSwQVcDJke_5X8X17p2m_kc/viewform',
  dwelling_fire:    'https://docs.google.com/forms/d/1xPRCet_wFHhITOHsa8aEcSc__n5gtXhf18SKuHUBoIM/viewform'
};

// Select the right form URL based on insurance type (default to auto)
const formUrl = FORM_URLS[insuranceType] || FORM_URLS['auto'];

// Friendly label for the SMS
const typeLabels = {
  auto: 'auto insurance', vehicle: 'auto insurance',
  commercial_auto: 'commercial auto insurance', business: 'commercial auto insurance',
  homeowners: 'home insurance', home: 'home insurance', property: 'home insurance',
  condo: 'condo insurance', renters: 'renters insurance',
  dwelling_fire: 'dwelling fire insurance'
};
const typeLabel = typeLabels[insuranceType] || 'insurance';

// SMS body
const smsBody = `Aloha ${callerName}! Mahalo for calling Equity Insurance. Please complete your ${typeLabel} quote form here: ${formUrl} - Call us at (808) 593-7746 with any questions!`;

return [{
  json: {
    to: e164Phone,
    body: smsBody,
    call_id: callId,
    caller_name: callerName,
    caller_phone: phone10,
    insurance_type: insuranceType,
    form_url: formUrl,
    toolCallId,
    error: false,
    sent_at: new Date().toISOString()
  }
}];

